package com.museumheist.game.progress;import com.museumheist.game.GameConfig;import com.museumheist.game.entity.PowerUp;import java.util.Arrays;public final class LoadoutSelection{public enum ToggleResult{SELECTED,REMOVED,FULL}private final PowerUp.Type[]slots=new PowerUp.Type[GameConfig.POWER_UP_SLOT_COUNT];public ToggleResult toggle(PowerUp.Type t){if(t==null)return ToggleResult.FULL;int e=indexOf(t);if(e>=0){slots[e]=null;compact();return ToggleResult.REMOVED;}for(int i=0;i<slots.length;i++)if(slots[i]==null){slots[i]=t;return ToggleResult.SELECTED;}return ToggleResult.FULL;}public boolean selectIfSpace(PowerUp.Type t){if(t==null||contains(t))return false;for(int i=0;i<slots.length;i++)if(slots[i]==null){slots[i]=t;return true;}return false;}public boolean contains(PowerUp.Type t){return indexOf(t)>=0;}public PowerUp.Type get(int i){return i>=0&&i<slots.length?slots[i]:null;}public int size(){int n=0;for(PowerUp.Type t:slots)if(t!=null)n++;return n;}public void restore(PowerUp.Type[]saved){Arrays.fill(slots,null);if(saved!=null)for(PowerUp.Type t:saved)selectIfSpace(t);}public void copyTo(PowerUp.Type[]target){if(target==null)return;Arrays.fill(target,null);System.arraycopy(slots,0,target,0,Math.min(slots.length,target.length));}private int indexOf(PowerUp.Type t){for(int i=0;i<slots.length;i++)if(slots[i]==t)return i;return-1;}private void compact(){int w=0;for(PowerUp.Type t:slots)if(t!=null)slots[w++]=t;while(w<slots.length)slots[w++]=null;}}
